Pseudo:
use client
import useState 불필요 (props 로 open/onOpenChange 받음)
import Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription from @/components/ui/sheet
import Button from @/components/ui/button
import Instagram, Twitter, MessageCircle, ExternalLink from lucide-react
import CircleDetail from @/lib/types/domain

const CHANNEL_META = {
  instagram: { label: 'Instagram', Icon: Instagram },
  x: { label: 'X (Twitter)', Icon: Twitter },
  line: { label: 'LINE', Icon: MessageCircle },
}

interface Props { circle: CircleDetail; open: boolean; onOpenChange: (v: boolean) => void }

export function JoinChannelModal({ circle, open, onOpenChange }) {
  const channels = []
  if (circle.contact_instagram) channels.push({ key: 'instagram', url: circle.contact_instagram })
  if (circle.contact_x) channels.push({ key: 'x', url: circle.contact_x })
  if (circle.contact_line) channels.push({ key: 'line', url: circle.contact_line })

  function handleChannelClick(key) {
    console.info('[T-009 anchor] incrementInquiryCount', circle.id, key)
    onOpenChange(false)
  }

  return Sheet(open, onOpenChange) {
    SheetContent(side=bottom, className=mx-auto max-w-md) {
      SheetHeader { SheetTitle: 参加方法を選んでください, SheetDescription: circle.name に問い合わせる連絡先を選んでください }
      if channels.length===0:
        <div class=py-6 text-center>
          <p>連絡先が登録されていません。</p>
          <Button variant=outline onClick={() => onOpenChange(false)}>閉じる</Button>
        </div>
      else:
        <ul class=space-y-2 py-4>
          for each ch:
            <li>
              <Button asChild className=h-12 w-full justify-start gap-3>
                <a href={ch.url} target=_blank rel=noopener noreferrer aria-label=`${CHANNEL_META[ch.key].label}で問い合わせる(外部リンク)` onClick={() => handleChannelClick(ch.key)}>
                  <Icon className=size-5 aria-hidden=true />
                  <span>{CHANNEL_META[ch.key].label}</span>
                  <ExternalLink className=ml-auto size-4 aria-hidden=true />
                </a>
              </Button>
            </li>
        </ul>
    }
  }
}

